export class ObjectPoolMap<K, V extends object> {
  private storage: V[] = [];
  private keyToIndex: Map<K, number> = new Map();
  private indexToKey: K[] = [];
  private obj: V;

  constructor(obj: V) {
    this.obj = obj;
  }

  size() {
    return this.indexToKey.length;
  }

  add(key: K): V {
    if (this.keyToIndex.has(key))
      return this.storage[this.keyToIndex.get(key) as number];
    if (this.storage.length <= this.indexToKey.length)
      this.storage.push(Object.assign({}, this.obj));
    this.keyToIndex.set(key, this.indexToKey.length);
    this.indexToKey.push(key);
    return this.storage[this.indexToKey.length - 1];
  }

  remove(key: K): void {
    const index = this.keyToIndex.get(key);
    if (index == undefined) return;
    const backKey = this.indexToKey[this.indexToKey.length - 1];
    const temp = this.storage[index];
    this.storage[index] = this.storage[this.indexToKey.length - 1];
    this.storage[this.indexToKey.length - 1] = temp;
    this.indexToKey[index] = backKey;
    this.indexToKey.pop();
    this.keyToIndex.set(backKey, index);
    this.keyToIndex.delete(key);
  }

  get(key: K): V {
    const index = this.keyToIndex.get(key);
    if (index == undefined) throw new Error("Key not found.");
    return this.storage[index];
  }

  has(key: K): boolean {
    return this.keyToIndex.has(key);
  }

  clean(): void {
    this.storage.splice(this.indexToKey.length);
  }

  clear(): void {
    this.storage.length = 0;
    this.keyToIndex.clear();
    this.indexToKey.length = 0;
  }
}
