import { ComponentManager } from "./component.ts";
import { newEntity, type entityT } from "./entity.ts";

export type queryT = Record<"and" | "not", object[]>;
export type systemT = (world: World) => void;

export class World {
  private compEntityMap: Map<object, Set<entityT>> = new Map();
  private compManager = new ComponentManager();
  private entitySet: Set<entityT> = new Set();

  static onAddComponent(
    world: World,
    entity: entityT,
    component: object,
  ): void {}

  static onRemoveComponent(
    world: World,
    entity: entityT,
    component: object,
  ): void {}

  addEntity(entity: entityT = newEntity()): entityT {
    this.entitySet.add(entity);
    return entity;
  }

  copyEntity(src: entityT, dest: entityT = newEntity()): entityT {
    this.compManager.copy(src, dest);
    for (const entry of this.compEntityMap) {
      if (!entry[1].has(src)) continue;
      World.onAddComponent(this, dest, entry[0]);
      entry[1].add(dest);
    }
    this.entitySet.add(dest);
    return dest;
  }

  private getCompEntityMap(comp: object): Set<entityT> {
    const a = this.compEntityMap.get(comp) ?? new Set();
    this.compEntityMap.set(comp, a);
    return a;
  }

  deleteEntity(entity: entityT) {
    for (const entry of this.compEntityMap) {
      if (!entry[1].has(entity)) continue;
      World.onRemoveComponent(this, entity, entry[0]);
      entry[1].delete(entity);
    }
    this.entitySet.delete(entity);
    this.compManager.delete(entity);
  }

  registerComponent<T extends object>(component: T): World {
    this.compManager.register(component);
    return this;
  }

  hasComponent<T extends object>(entity: entityT, component: T): boolean {
    return this.compManager.has(entity, component);
  }

  addComponent<T extends object>(
    entity: entityT,
    component: T,
    values: Partial<T> = component,
  ): T {
    this.compManager.register(component);
    this.getCompEntityMap(component).add(entity);
    World.onAddComponent(this, entity, component);
    return Object.assign(this.compManager.add(entity, component), values);
  }

  removeComponent<T extends object>(entity: entityT, component: T): void {
    this.compManager.register(component);
    const cem = this.getCompEntityMap(component);
    if (!cem.has(entity)) return;
    World.onRemoveComponent(this, entity, component);
    cem.delete(entity);
    this.compManager.remove(entity, component);
  }

  getComponent<T extends object>(entity: entityT, component: T): T {
    return this.compManager.get(entity, component);
  }

  copyEntityTo(anotherWorld: World, entity: entityT) {
    if (anotherWorld == this) return;
    for (const comp of this.compEntityMap) {
      if (!comp[1].has(entity)) continue;
      anotherWorld.addComponent(
        entity,
        comp[0],
        this.getComponent(entity, comp[0]),
      );
    }
  }

  copyComponentTo<T extends object>(
    anotherWorld: World,
    entity: entityT,
    component: T,
  ) {
    anotherWorld.addComponent(
      entity,
      component,
      this.getComponent(entity, component),
    );
  }

  clear() {
    this.entitySet.forEach((e) => {
      this.deleteEntity(e);
    });
    this.entitySet.clear();
  }

  update(fns: systemT[]) {
    for (let i = 0, l = fns.length; i < l; i++) fns[i](this);
  }

  cleanObjectPools(): void {
    this.compManager.clean();
  }

  query(query: Partial<queryT>): entityT[] {
    let res: Set<entityT> = this.entitySet;
    if (query.and) {
      for (const comp of query.and) {
        res = res.intersection(this.getCompEntityMap(comp));
      }
    }
    if (query.not) {
      for (const comp of query.not) {
        res = res.difference(this.getCompEntityMap(comp));
      }
    }
    return Array.from(res);
  }

  entityCount(): number {
    return this.entitySet.size;
  }
}
